/* ────────────────────────────────────────────────────────
   ③ WHO WE ARE — cinematic fullscreen scroll panels
   Each panel = full viewport takeover with:
   • Split headline bursts up from below
   • Coloured accent bar slams in from left
   • Body text fades up
   • Background image cross-fades per panel
   • Left column shows fixed "WHO WE ARE" + step nav
──────────────────────────────────────────────────────── */
const WHO_BG = [
  'https://images.unsplash.com/photo-1497366216548-37526070297c?w=1600&q=80',
  'https://images.unsplash.com/photo-1522071820081-009f0129c71c?w=1600&q=80',
  'https://images.unsplash.com/photo-1600880292203-757bb62b4baf?w=1600&q=80',
];
const WHO_COLORS = ['#0057ff', '#7c3aed', '#db2777'];
const WHO_RGB    = ['0,87,255', '124,58,237', '219,39,119'];

function WhoWeAre() {
  const wRef = useRef(null);
  const prog = useScrollProg(wRef);

  // Each panel occupies 1/3 of total scroll
  const total = WHO_PANELS.length;
  const idx   = Math.min(total - 1, Math.floor(prog * total));

  // Progress within the current panel (0→1)
  const panelProg = (prog * total) - idx;

  // For each panel: enter = 0→0.35, hold = 0.35→0.75, exit = 0.75→1
  const enter = Math.min(1, panelProg / 0.35);
  const exit  = Math.max(0, (panelProg - 0.75) / 0.25);

  const col = WHO_COLORS[idx];
  const rgb = WHO_RGB[idx];

  // Eased enter
  const eEnter = 1 - Math.pow(1 - enter, 3);
  const eExit  = Math.pow(exit, 2);

  return (
    <div ref={wRef} style={{ height: `${total * 140}vh`, position: 'relative' }}>
      <section style={{ position: 'sticky', top: 0, height: '100vh', overflow: 'hidden', background: '#020810' }}>

        {/* ══ BACKGROUND images — cross-fade per panel ══ */}
        {WHO_BG.map((src, i) => (
          <div key={i} style={{ position: 'absolute', inset: 0, opacity: idx === i ? 1 : 0, transition: 'opacity .9s cubic-bezier(.4,0,.2,1)', willChange: 'opacity' }}>
            <img src={src} alt="" style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', objectFit: 'cover', filter: 'saturate(.35) brightness(.18)' }} />
          </div>
        ))}

        {/* Gradient overlay — left half darker for text legibility */}
        <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(105deg, rgba(2,8,16,.97) 0%, rgba(2,8,16,.88) 45%, rgba(2,8,16,.35) 100%)', pointerEvents: 'none' }} />

        {/* Coloured ambient glow — shifts per panel */}
        <div style={{ position: 'absolute', top: '30%', left: '25%', width: '40vw', height: '40vw', borderRadius: '50%', background: `radial-gradient(ellipse, rgba(${rgb},.14) 0%, transparent 70%)`, transform: 'translateZ(0)', transition: 'background .8s ease', willChange: 'opacity' }} />

        {/* ══ LEFT COLUMN — fixed label + step nav ══ */}
        <div style={{ position: 'absolute', left: 'clamp(28px,6vw,80px)', top: '50%', transform: 'translateY(-50%) translateZ(0)', zIndex: 3, display: 'flex', flexDirection: 'column', gap: 0 }}>

          {/* Section label — vertical */}
          <div style={{ writingMode: 'vertical-rl', textOrientation: 'mixed', transform: 'rotate(180deg)', fontSize: '.6rem', fontWeight: 700, letterSpacing: '.24em', textTransform: 'uppercase', color: 'rgba(255,255,255,.25)', marginBottom: 28 }}>
            Who We Are
          </div>

          {/* Step pills */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            {WHO_PANELS.map((p, i) => {
              const active = i === idx;
              return (
                <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 10, opacity: active ? 1 : 0.3, transform: `translateZ(0)`, transition: 'opacity .4s ease' }}>
                  {/* Dot */}
                  <div style={{ width: active ? 28 : 6, height: 4, borderRadius: 2, background: active ? col : 'rgba(255,255,255,.3)', transformOrigin: 'left', transition: 'width .4s cubic-bezier(.16,1,.3,1), background .4s ease', willChange: 'width' }} />
                  {active && (
                    <span style={{ fontSize: '.6rem', fontWeight: 700, letterSpacing: '.12em', textTransform: 'uppercase', color: 'rgba(255,255,255,.5)', whiteSpace: 'nowrap' }}>
                      {String(i + 1).padStart(2, '0')} / {String(total).padStart(2, '0')}
                    </span>
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {/* ══ MAIN CONTENT — per-panel cinematic reveal ══ */}
        <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', padding: '0 clamp(100px,12vw,160px) 0 clamp(90px,10vw,140px)', zIndex: 2 }}>
          <div style={{ maxWidth: 720, width: '100%' }}>

            {/* Accent bar — slams in from left */}
            <div style={{ height: 4, borderRadius: 2, background: `linear-gradient(to right, ${col}, transparent)`, marginBottom: 36, width: '100%', transformOrigin: 'left', transform: `scaleX(${eEnter * (1 - eExit * 1.5)}) translateZ(0)`, willChange: 'transform', transition: 'background .6s ease' }} />

            {/* Panel content — stack & cross-fade */}
            <div style={{ position: 'relative', minHeight: 'clamp(280px,40vh,420px)' }}>
              {WHO_PANELS.map((p, i) => {
                const isActive = i === idx;
                const wasActive = i === idx - 1;
                // Active panel: slides up in, then slides up out on exit
                const yIn  = isActive ? (1 - eEnter) * 60 : 0;
                const yOut = isActive ? eExit * -50 : 0;
                const oVal = isActive ? eEnter * (1 - eExit * 2) : 0;

                return (
                  <div key={i} style={{ position: 'absolute', top: 0, left: 0, right: 0, opacity: Math.max(0, oVal), transform: `translateY(${yIn + yOut}px) translateZ(0)`, willChange: 'opacity,transform', pointerEvents: isActive ? 'auto' : 'none' }}>

                    {/* Panel number — huge ghost */}
                    <div style={{ position: 'absolute', top: -20, right: 0, fontFamily: 'var(--serif)', fontSize: 'clamp(7rem,15vw,13rem)', fontWeight: 900, color: `rgba(${rgb},.08)`, lineHeight: 1, letterSpacing: '-.06em', userSelect: 'none', pointerEvents: 'none' }}>
                      {p.num}
                    </div>

                    {/* Title — large, crisp, high contrast */}
                    <h2 style={{ fontFamily: 'var(--serif)', fontSize: 'clamp(2.8rem,6.5vw,6rem)', fontWeight: 900, color: '#ffffff', letterSpacing: '-.04em', lineHeight: 1.0, marginBottom: 28, position: 'relative', zIndex: 1, textShadow: '0 2px 40px rgba(0,0,0,.8)' }}>
                      {p.title.split(' ').map((word, wi) => (
                        <span key={wi} style={{ display: 'inline-block', marginRight: '0.28em', transform: `translateY(${(1 - eEnter) * (20 + wi * 12)}px) translateZ(0)`, opacity: eEnter > wi * 0.12 ? 1 : 0, willChange: 'opacity,transform', transition: 'none' }}>
                          {word}
                        </span>
                      ))}
                    </h2>

                    {/* Thin divider */}
                    <div style={{ width: 48, height: 2, borderRadius: 1, background: col, marginBottom: 24, transition: 'background .6s ease' }} />

                    {/* Body — crisp, generous size */}
                    <p style={{ fontSize: 'clamp(1rem,1.6vw,1.18rem)', color: 'rgba(255,255,255,.72)', lineHeight: 1.9, maxWidth: 560, fontWeight: 400, opacity: eEnter > 0.4 ? (eEnter - 0.4) / 0.6 : 0, transform: `translateY(${(1 - Math.min(1,(eEnter - 0.4) / 0.6)) * 20}px) translateZ(0)`, willChange: 'opacity,transform' }}>
                      {p.body}
                    </p>

                  </div>
                );
              })}
            </div>

          </div>
        </div>

        {/* ══ BOTTOM — progress track ══ */}
        <div style={{ position: 'absolute', bottom: 32, left: 'clamp(90px,10vw,140px)', right: 'clamp(28px,6vw,80px)', display: 'flex', alignItems: 'center', gap: 16, zIndex: 3 }}>
          <div style={{ flex: 1, height: 1, background: 'rgba(255,255,255,.08)', position: 'relative', overflow: 'hidden', borderRadius: 1 }}>
            <div style={{ position: 'absolute', inset: 0, background: `linear-gradient(to right,${col},#7c3aed)`, transformOrigin: 'left', transform: `scaleX(${prog}) translateZ(0)`, willChange: 'transform', transition: 'background .6s ease' }} />
          </div>
          <span style={{ fontSize: '.6rem', fontWeight: 700, letterSpacing: '.16em', color: 'rgba(255,255,255,.25)', whiteSpace: 'nowrap' }}>
            {String(idx + 1).padStart(2, '0')} &nbsp;/&nbsp; {String(total).padStart(2, '0')}
          </span>
        </div>

      </section>
    </div>
  );
}

